    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it.todo("quote a plain amulet for a newcomer first insurance → 60 + 6 + 5 = 71 G");
  it.todo("quote a plain staff for a newcomer first insurance → 80 + 8 + 5 = 93 G");
  it.todo("quote a plain potion for a newcomer first insurance → 40 + 4 + 5 = 49 G");

