const PROCESSING_FEE = 5;
const INITIAL_ASSESSMENT_SURCHARGE_RATE = 0.1;

type Item = { type: string };
type QuoteStep = { op: "quote"; items: Item[] };
type Scenario = {
  customer: { yearsWithMHPCO: number };
  steps: QuoteStep[];
};
type QuoteResult = { premium: number };
type ScenarioResult = { results: QuoteResult[] };

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const sumBasePremiums = (items: Item[]): number =>
  items.reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);

const quotePremium = (items: Item[]): number => {
  const base = sumBasePremiums(items);
  const surcharge = base * INITIAL_ASSESSMENT_SURCHARGE_RATE;
  return Math.ceil(base + surcharge) + PROCESSING_FEE;
};

export const runScenario = (input: Scenario): ScenarioResult => {
  const results = input.steps.map((step) => ({ premium: quotePremium(step.items) }));
  return { results };
};

